def _call_cortex_direct(self, prompt: str, model: str) -> Optional[str]:
        """Cortex API を TokenVault + urllib で直叩き (stdlib only, no httpx)"""
        import urllib.request
        import json as _json

        try:
            from mekhane.ochema.token_vault import TokenVault
            vault = TokenVault()
            creds = vault.get_token("default")
            if isinstance(creds, tuple):
                token = creds[0]
                project = creds[1] if len(creds) > 1 else None
            else:
                token = str(creds)
                project = None

            if not token:
                return None

            # Cortex generateContent endpoint
            base = "https://daily-cloudcode-pa.googleapis.com/v1internal"
            url = f"{base}/projects/{project}/locations/global/publishers/google/models/{model}:generateContent"

            body = _json.dumps({
                "contents": [{"role": "user", "parts": [{"text": prompt}]}],
                "generationConfig": {"maxOutputTokens": 8192},
            }).encode()

            req = urllib.request.Request(
                url,
                data=body,
                headers={
                    "Authorization": f"Bearer {token}",
                    "Content-Type": "application/json",
                },
                method="POST",
            )

            with urllib.request.urlopen(req, timeout=60) as resp:
                data = _json.loads(resp.read())

            candidates = data.get("candidates", [])
            if candidates:
                parts = candidates[0].get("content", {}).get("parts", [])
                if parts:
                    return parts[0].get("text", "")
            return None
        except Exception:
            return None

def parse_period(period_str: str) -> Optional[datetime]:
        """期間文字列をパース"""
        now = datetime.now()
        if period_str == "today":
            return now.replace(hour=0, minute=0, second=0)
        elif period_str == "last_24h":
            from datetime import timedelta
            return now - timedelta(hours=24)
        elif period_str == "last_7_days":
            from datetime import timedelta
            return now - timedelta(days=7)
        elif period_str == "last_30_days":
            from datetime import timedelta
            return now - timedelta(days=30)
