        """ツールを実行"""
        try:
            if name == "hermeneus_execute":
                result = await _handle_execute(arguments)
            elif name == "hermeneus_compile":
                result = await _handle_compile(arguments)
            elif name == "hermeneus_audit":
                result = await _handle_audit(arguments)
            elif name == "hermeneus_list_workflows":
